<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Sorting Algorithm Visualizer</title>
<style>
  body {
    margin:0;
    padding:0;
    background:#121212;
    color:#eee;
    font-family:Arial,Helvetica,sans-serif;
    display:flex;
    flex-direction:column;
    align-items:center;
    height:100vh;
    overflow:hidden;
  }
  #controls {
    margin:10px;
  }
  button {
    background:#333;
    color:#eee;
    border:none;
    padding:8px 16px;
    margin:0 5px;
    cursor:pointer;
    border-radius:4px;
    font-size:14px;
  }
  button:hover {background:#444;}
  #bars {
    flex:1;
    display:flex;
    align-items:flex-end;
    width:90%;
    max-width:900px;
    margin-top:10px;
    gap:2px;
    overflow:hidden;
  }
  .bar {
    background:#4caf50;
    width:100%;
    transition:background 0.2s, height 0.2s;
  }
  .comparing {background:#ff9800 !important;}
  .swapped   {background:#f44336 !important;}
</style>
</head>
<body>
<div id="controls">
  <button id="shuffle">Shuffle</button>
  <button id="reset">Reset</button>
  <button id="sort">Sort</button>
</div>
<div id="bars"></div>

<script>
(() => {
  const MAX_VAL = 100;
  const BAR_COUNT = 50;
  let arr = [];
  let original = [];
  const barsContainer = document.getElementById('bars');

  // ---------- Rendering ----------
  function render() {
    barsContainer.innerHTML = '';
    const width = Math.floor( (barsContainer.clientWidth - (BAR_COUNT-1)*2) / BAR_COUNT );
    arr.forEach(v => {
      const bar = document.createElement('div');
      bar.className = 'bar';
      bar.style.height = (v / MAX_VAL * 100) + '%';
      bar.style.width = width + 'px';
      barsContainer.appendChild(bar);
    });
  }

  // ---------- Utility ----------
  function isSorted() {
    for (let i = 1; i < arr.length; i++) {
      if (arr[i-1] > arr[i]) return false;
    }
    return true;
  }

  // ---------- API ----------
  window.viz = {
    array() { return arr.slice(); },
    setArray(a) {
      arr = a.slice();
      render();
    },
    sorted() { return isSorted(); },
    sortStep: (function() {
      // bubble sort state
      let i = 0, j = 0;
      return function() {
        if (arr.length < 2) return true;
        if (i >= arr.length - 1) {
          // already sorted
          clearHighlights();
          return true;
        }
        // highlight compared bars
        clearHighlights();
        const bars = barsContainer.children;
        bars[j].classList.add('comparing');
        bars[j+1].classList.add('comparing');

        if (arr[j] > arr[j+1]) {
          // swap
          [arr[j], arr[j+1]] = [arr[j+1], arr[j]];
          // update heights
          const h1 = (arr[j] / MAX_VAL * 100) + '%';
          const h2 = (arr[j+1] / MAX_VAL * 100) + '%';
          bars[j].style.height = h1;
          bars[j+1].style.height = h2;
          bars[j].classList.add('swapped');
          bars[j+1].classList.add('swapped');
        }

        j++;
        if (j >= arr.length - i - 1) {
          j = 0;
          i++;
        }
        // if finished
        if (i >= arr.length - 1) {
          clearHighlights();
          return true;
        }
        return false;
      };
    })()
  };

  function clearHighlights() {
    const bars = barsContainer.children;
    for (let b of bars) {
      b.classList.remove('comparing','swapped');
    }
  }

  // ---------- Controls ----------
  function shuffleArray() {
    const a = [];
    for (let i = 0; i < BAR_COUNT; i++) {
      a.push(Math.floor(Math.random()*MAX_VAL)+1);
    }
    original = a.slice();
    window.viz.setArray(a);
  }

  function resetArray() {
    window.viz.setArray(original);
  }

  document.getElementById('shuffle').addEventListener('click', shuffleArray);
  document.getElementById('reset').addEventListener('click', resetArray);
  document.getElementById('sort').addEventListener('click', () => {
    const interval = setInterval(() => {
      const done = window.viz.sortStep();
      if (done) {
        clearInterval(interval);
      }
    }, 30);
  });

  // ---------- Init ----------
  shuffleArray();
})();
</script>
</body>
</html>
